              { type: "rune" },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 55 });
    });
    it.todo("applies block discount for exactly 3 alike components (3 runes = 60 + 5 = 65)");
