    it.todo("applies item-level modifiers only to the affected item in a multi-item policy");
  });

  describe("Quote - policy-wide modifiers", () => {
    it.todo("applies 10% first insurance surcharge on policy base premium sum");
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up discount on second and subsequent quotes");
    it.todo("stacks all policy-wide modifiers (loyalty + first insurance + follow-up)");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up in MHPCO favor (ceiling)");
  });

  describe("Quote - errors", () => {
    it.todo("rejects unknown item type with an error");
  });

  describe("Claim - standard reimbursement", () => {
    it.todo("applies 100G deductible per damaged item (500 damage to sword = 400 payout)");
    it.todo("returns remaining cap after payout");
    it.todo("reimburses component damage with deductible (200 damage to rune = 100 payout)");
  });

  describe("Claim - enchantment and material clauses", () => {
    it.todo("reimburses at 50% for enchantment >= 8 then applies deductible");
    it.todo("fully reimburses dragon material items then applies deductible");
    it.todo("applies 50% rule when both high enchantment >= 8 and dragon material");
    it.todo("does not apply enchantment clause below enchantment 8");
  });

  describe("Claim - cap and multiple damages", () => {
    it.todo("applies deductible separately per damaged item in same event");
    it.todo("caps total payout at 2x insurance sum across multiple claims");
    it.todo("reduces payout to remaining cap when cap would be exceeded");
  });

  describe("Claim - errors", () => {
    it.todo("rejects damage for item not covered by the policy");
    it.todo("rejects more damage entries of a type than policy covers");
    it.todo("rejects negative damage amount");
  });

  describe("Integration - newcomer cursed sword", () => {
    it.todo("computes 165G for newcomer with cursed sword (100 + 50 curse + 10 first ins + 5 fee)");
  });

  describe("Integration - long-standing customer second contract", () => {
    it.todo("computes 160G for long-standing customer second contract with cursed high-ench sword");
  });
});

