const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const MAIN_ITEM_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune"]);

const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);

const sumBasePremiums = (items: any[]): number => {
  let total = 0;
  const componentCounts: Record<string, number> = {};

  for (const item of items) {
    if (isComponent(item)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
    }
  }

  for (const count of Object.values(componentCounts)) {
    if (count === COMPONENT_BLOCK_SIZE) {
      total += COMPONENT_BLOCK_PREMIUM;
    } else {
      total += count * COMPONENT_PREMIUM;
    }
  }

  return total;
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => ({
    premium: PROCESSING_FEE + sumBasePremiums(step.items),
  }));
  return { results };
};

