export const processScenario = (scenario: any): any => {
  const results: any[] = [];
  let quoteCount = 0;
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const basePremiumSum = calculateBasePremiumSum(step.items);
      const itemSurcharges = calculateItemLevelSurcharges(step.items);
      const firstInsurance = basePremiumSum * FIRST_INSURANCE_RATE;
      const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= 2 ? basePremiumSum * 0.2 : 0;
      const followUpDiscount = quoteCount > 0 ? basePremiumSum * 0.15 : 0;
      const premium = Math.ceil(basePremiumSum + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
      results.push({ premium });
      quoteCount++;
    }
  }
  return { results };
};

