    (sum, count) => sum + componentGroupPremium(count),
    0,
  );

  return mainBaseTotal + componentTotal;
};

const calculateItemLevelSurcharges = (items: any[]): number => {
  const mainItems = items.filter((item) => !isComponent(item));
  return mainItems.reduce((sum, item) => {
    const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
    const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
    const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
    return sum + cursedSurcharge + enchantmentSurcharge;
  }, 0);
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => {
    const basePremiumSum = calculateBasePremiumSum(step.items);
    const itemSurcharges = calculateItemLevelSurcharges(step.items);
    const firstInsurance = basePremiumSum * FIRST_INSURANCE_RATE;
    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= 2 ? basePremiumSum * 0.2 : 0;
    const premium = Math.ceil(basePremiumSum + itemSurcharges + firstInsurance - loyaltyDiscount + PROCESSING_FEE);
    return { premium };
  });
  return { results };
};

