const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const FIRST_INSURANCE_RATE = 0.1;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;

const MAIN_ITEM_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);

const componentGroupPremium = (count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : count * COMPONENT_PREMIUM;

const calculateBasePremiumSum = (items: any[]): number => {
  const mainItems = items.filter((item) => !isComponent(item));
  const components = items.filter(isComponent);

  const mainBaseTotal = mainItems.reduce(
    (sum, item) => sum + (MAIN_ITEM_PREMIUMS[item.type] ?? 0),
    0,
  );

  const componentCounts: Record<string, number> = {};
  for (const item of components) {
    componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
  }

  const componentTotal = Object.values(componentCounts).reduce(
    (sum, count) => sum + componentGroupPremium(count),
    0,
  );

  return mainBaseTotal + componentTotal;
};

const calculateItemLevelSurcharges = (items: any[]): number => {
  const mainItems = items.filter((item) => !isComponent(item));
  return mainItems.reduce((sum, item) => {
    const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
    const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
    const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
    return sum + cursedSurcharge + enchantmentSurcharge;
  }, 0);
};

export const processScenario = (scenario: any): any => {
  const results: any[] = [];
  let quoteCount = 0;
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const basePremiumSum = calculateBasePremiumSum(step.items);
      const itemSurcharges = calculateItemLevelSurcharges(step.items);
      const firstInsurance = basePremiumSum * FIRST_INSURANCE_RATE;
      const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremiumSum * LOYALTY_DISCOUNT_RATE : 0;
      const followUpDiscount = quoteCount > 0 ? basePremiumSum * FOLLOW_UP_DISCOUNT_RATE : 0;
      const premium = Math.ceil(basePremiumSum + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
      results.push({ premium });
      quoteCount++;
    }
  }
  return { results };
};

